+/// List path mappings for a source (P6.3)
+fn run_mappings_list(source_name: &str, json_output: bool) -> CliResult<()> {
+    use crate::sources::config::SourcesConfig;
+
+    let config = SourcesConfig::load().map_err(|e| CliError {
